import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  adminGetAllUsers, adminDeleteTargetUser, adminUpdateUserData,
  fetchLiveProducts, adminAddProduct, adminUpdateProduct, adminDeleteProduct
} from '../utils/api';
import ImageUploader from './ImageUploader'; // ✅ Import your media storage node component

function AdminPanel({ user }) {
  const cachedSession = sessionStorage.getItem("currentUser");
  const sessionObj = cachedSession ? JSON.parse(cachedSession) : null;

  const isSessionValid =
    sessionObj &&
    sessionObj.role === "admin" &&
    sessionObj.token &&
    sessionObj.token.startsWith("admin-secure-session");

  const navigate = useNavigate();

  // User Management States
  const [activeTab, setActiveTab] = useState("users");
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [editRole, setEditRole] = useState("");
  const [editEmail, setEditEmail] = useState("");

  // Product Management States
  const [products, setProducts] = useState([]);
  const [pName, setPName] = useState("");
  const [pPrice, setPPrice] = useState("");
  const [pDesc, setPDesc] = useState("");
  const [pStock, setPStock] = useState("");
  const [pImage, setPImage] = useState(""); // Tracks uploaded Cloudinary image path string
  const [editingProductId, setEditingProductId] = useState(null);

  // ✅ NEW: Tracks live administrative notifications with auto-expiring states
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    if (!isSessionValid) {
      alert("⛔ Security Violation Intercepted: Multi-tab cloning rejected. Please authenticate with a valid 2FA token on this page layout view.");
      sessionStorage.removeItem("currentUser");
      navigate("/login");
    } else {
      refreshUserList();
      refreshProductList();
    }
  }, [navigate, isSessionValid]);

  // =========================================================================
  // 🔔 NEW: ISOLATED ADMIN-ONLY WEBSOCKET LISTENER SYSTEM WITH 5-SECOND TIMER
  // =========================================================================
  useEffect(() => {
    if (!isSessionValid) return;

    // Checks if the workspace layout globally mounts your socket pipeline reference
    const activeSocket = window.socket; 

    if (activeSocket) {
      const handleIncomingNotification = (data) => {
        const uniqueId = Date.now() + Math.random();
        const notificationPayload = { ...data, id: uniqueId };

        // Append the incoming event banner into the visible queue
        setNotifications((prev) => [...prev, notificationPayload]);

        // ⏱️ Auto-clear this specific banner card instance after exactly 5 seconds
        setTimeout(() => {
          setNotifications((prev) => prev.filter((item) => item.id !== uniqueId));
        }, 5000);
      };

      activeSocket.on("system_notification", handleIncomingNotification);

      // Cleanup subscription hook on unmount
      return () => {
        activeSocket.off("system_notification", handleIncomingNotification);
      };
    }
  }, [isSessionValid]);

  function refreshUserList() {
    adminGetAllUsers().then(data => { if (Array.isArray(data)) setUsers(data); }).catch(err => console.error(err));
  }

  function refreshProductList() {
    fetchLiveProducts().then(data => { if (Array.isArray(data)) setProducts(data); }).catch(err => console.error(err));
  }

  if (!isSessionValid) {
    return null;
  }

  // ==========================================
  // USER MANAGEMENT ACTIONS
  // ==========================================
  function handleSelectUser(u) {
    setSelectedUser(u);
    setEditRole(u.role);
    setEditEmail(u.email);
  }

  function handleSaveUserChanges(username) {
    adminUpdateUserData(username, { email: editEmail, role: editRole })
      .then(res => {
        if (res.success) {
          alert("User properties modified successfully!");
          refreshUserList();
          setSelectedUser(null);
        } else {
          alert(res.error || "Failed to update user.");
        }
      }).catch(err => console.error(err));
  }

  // ==========================================
  // PRODUCT MANAGEMENT ACTIONS
  // ==========================================
  function handleProductSubmit(e) {
    e.preventDefault();

    const payload = {
      name: pName,
      price: parseFloat(pPrice),
      description: pDesc,
      stock: parseInt(pStock),
      image: pImage || ""
    };

    if (editingProductId) {
      adminUpdateProduct(editingProductId, payload).then(res => {
        if (res.success) {
          alert("Store product properties adjusted successfully!");
          resetProductForm();
          refreshProductList();
        }
      }).catch(err => console.error(err));
    } else {
      adminAddProduct(payload).then(res => {
        if (res.success) {
          alert("Product injected to sales catalog system!");
          resetProductForm();
          refreshProductList();
        }
      }).catch(err => console.error(err));
    }
  }

  function handleEditProductClick(product) {
    setEditingProductId(product.id);
    setPName(product.name);
    setPPrice(product.price);
    setPDesc(product.description || "");
    setPStock(product.stock || 0);
    setPImage(product.image || "");
  }

  function resetProductForm() {
    setPName(""); setPPrice(""); setPDesc(""); setPStock("");
    setPImage("");
    setEditingProductId(null);
  }

  return (
    <div style={{ padding: "30px", maxWidth: "1100px", margin: "auto", fontFamily: "sans-serif", position: "relative" }}>
      <h2>System Administrator Command Center Workspace</h2>

      {/* Tab Switcher Navigation Layout */}
      <div style={{ marginBottom: "25px" }}>
        <button onClick={() => setActiveTab("users")} style={{ padding: "10px 20px", marginRight: "10px", background: activeTab === "users" ? "#007bff" : "#6c757d", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" }}>Manage User Accounts</button>
        <button onClick={() => setActiveTab("products")} style={{ padding: "10px 20px", background: activeTab === "products" ? "#28a745" : "#6c757d", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" }}>Product Inventory Editor</button>
      </div>

      {activeTab === "users" ? (
        <div>
          <h3>User Profiles Management Datatable</h3>
          <table style={{ width: "100%", borderCollapse: "collapse", marginTop: "15px" }}>
            <thead>
              <tr style={{ background: "#343a40", color: "#fff", textAlign: "left" }}>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Username</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Email Address</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Current Role</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u.username} style={{ borderBottom: "1px solid #ddd" }}>
                  <td style={{ padding: "12px", border: "1px solid #ddd" }}>{u.username}</td>
                  <td style={{ padding: "12px", border: "1px solid #ddd" }}>{u.email}</td>
                  <td style={{ padding: "12px", border: "1px solid #ddd" }}><strong style={{ color: u.role === "admin" ? "#dc3545" : "#333" }}>{u.role}</strong></td>
                  <td style={{ padding: "12px", border: "1px solid #ddd" }}>
                    <button onClick={() => handleSelectUser(u)} style={{ marginRight: "8px", background: "#17a2b8", color: "#fff", border: "none", padding: "6px 12px", borderRadius: "4px", cursor: "pointer" }}>Edit / Inspect</button>
                    <button onClick={() => { if (window.confirm(`Drop profile layout context for ${u.username}?`)) adminDeleteTargetUser(u.username).then(() => refreshUserList()); }} style={{ background: "#dc3545", color: "#fff", border: "none", padding: "6px 12px", borderRadius: "4px", cursor: "pointer" }}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {selectedUser && (
            <div style={{ marginTop: "25px", border: "1px solid #007bff", padding: "20px", borderRadius: "8px", backgroundColor: "#fbfdff" }}>
              <h4>Modify Account Context: <span style={{ color: "#007bff" }}>{selectedUser.username}</span></h4>

              <div style={{ marginBottom: "15px" }}>
                <label style={{ display: "block", marginBottom: "5px", fontWeight: "bold" }}>Modify Registered Email:</label>
                <input
                  type="email"
                  value={editEmail}
                  onChange={e => setEditEmail(e.target.value)}
                  style={{ width: "100%", maxWidth: "400px", padding: "8px", borderRadius: "4px", border: "1px solid #ccc" }}
                  required
                />
              </div>

              <div style={{ marginBottom: "20px" }}>
                <label style={{ display: "block", marginBottom: "5px", fontWeight: "bold" }}>Adjust Authority Tier Role Level:</label>
                <select value={editRole} onChange={e => setEditRole(e.target.value)} style={{ padding: "8px", width: "100%", maxWidth: "400px", borderRadius: "4px", border: "1px solid #ccc" }}>
                  <option value="user">User (Standard Access)</option>
                  <option value="admin">Admin (Master Credentials)</option>
                </select>
              </div>

              <button onClick={() => handleSaveUserChanges(selectedUser.username)} style={{ background: "#28a745", color: "#fff", padding: "8px 16px", border: "none", borderRadius: "4px", marginRight: "10px", cursor: "pointer" }}>Save Settings Changes</button>
              <button onClick={() => setSelectedUser(null)} style={{ background: "#6c757d", color: "#fff", padding: "8px 16px", border: "none", borderRadius: "4px", cursor: "pointer" }}>Cancel</button>
            </div>
          )}
        </div>
      ) : (
        /* TAB 2: PRODUCT MANAGEMENT CRUD VIEW */
        <div>
          <h3>{editingProductId ? `🔄 Edit Store Item (ID: ${editingProductId})` : "➕ Append New Product to Catalog"}</h3>
          <form onSubmit={handleProductSubmit} style={{ background: "#f8f9fa", padding: "25px", borderRadius: "8px", marginBottom: "35px", border: "1px solid #eee" }}>

            {/* Name & Price Row */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "15px", marginBottom: "15px" }}>
              <input type="text" placeholder="Product Title / Name" value={pName} onChange={e => setPName(e.target.value)} style={{ padding: "10px", borderRadius: "4px", border: "1px solid #ccc" }} required />
              <input type="number" step="0.01" placeholder="Sales Retail Price ($)" value={pPrice} onChange={e => setPPrice(e.target.value)} style={{ padding: "10px", borderRadius: "4px", border: "1px solid #ccc" }} required />
            </div>

            {/* Warehouse Stock Row */}
            <div style={{ marginBottom: "15px" }}>
              <input type="number" placeholder="Available Warehouse Stock Units" value={pStock} onChange={e => setPStock(e.target.value)} style={{ width: "100%", boxSizing: "border-box", padding: "10px", borderRadius: "4px", border: "1px solid #ccc" }} required />
            </div>

            {/* ✅ CLOUDINARY INTEGRATION MEDIA FIELD */}
            <div style={{ marginBottom: "15px" }}>
              <ImageUploader onUploadSuccess={(url) => setPImage(url)} />
              {pImage && (
                <div style={{ marginTop: "10px", fontSize: "14px", color: "green" }}>
                  ✅ File Stored! Preview: <br />
                  <img src={pImage} alt="Uploaded product preview" style={{ maxWidth: "120px", height: "auto", borderRadius: "4px", marginTop: "5px", border: "1px solid #ddd" }} />
                </div>
              )}
            </div>

            {/* Product Description Row */}
            <div style={{ marginBottom: "15px" }}>
              <textarea placeholder="Product Description Context Summary" value={pDesc} onChange={e => setPDesc(e.target.value)} style={{ width: "100%", boxSizing: "border-box", padding: "10px", borderRadius: "4px", border: "1px solid #ccc", minHeight: "80px" }} />
            </div>

            <button type="submit" style={{ background: editingProductId ? "#ffc107" : "#28a745", color: editingProductId ? "#000" : "#fff", padding: "10px 20px", border: "none", borderRadius: "4px", fontWeight: "bold", cursor: "pointer", marginRight: "10px" }}>
              {editingProductId ? "Commit System Updates" : "Publish Global Live Product Item"}
            </button>
            {editingProductId && <button type="button" onClick={resetProductForm} style={{ background: "#6c757d", color: "#fff", padding: "10px 20px", border: "none", borderRadius: "4px", cursor: "pointer" }}>Exit Edit State</button>}
          </form>

          <h3>Active Live Store Catalog Items ({products.length})</h3>
          <table style={{ width: "100%", borderCollapse: "collapse", marginTop: "15px" }}>
            <thead>
              <tr style={{ background: "#212529", color: "#fff", textAlign: "left" }}>
                <th style={{ padding: "12px", border: "1px solid #ddd", width: "80px" }}>Image</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Product Name</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Price</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Stock Inventory</th>
                <th style={{ padding: "12px", border: "1px solid #ddd" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {products.length === 0 ? (
                <tr><td colSpan="5" style={{ padding: "15px", textAlign: "center", color: "#666" }}>Inventory is completely empty right now. Add a product above!</td></tr>
              ) : (
                products.map(prod => (
                  <tr key={prod.id} style={{ borderBottom: "1px solid #ddd" }}>
                    <td style={{ padding: "12px", border: "1px solid #ddd", textAlign: "center", verticalAlign: "middle" }}>
                      <div style={{ width: "50px", height: "50px", backgroundColor: "#f0f2f5", borderRadius: "4px", overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", border: "1px solid #eaeaea", margin: "auto" }}>
                        {prod.image ? (
                          <img
                            src={prod.image}
                            alt={prod.name}
                            style={{ width: "100%", height: "100%", objectFit: "cover" }}
                          />
                        ) : (
                          <span style={{ fontSize: "10px", color: "#999" }}>📷 No Img</span>
                        )}
                      </div>
                    </td>
                    <td style={{ padding: "12px", border: "1px solid #ddd", verticalAlign: "middle" }}>
                      <strong>{prod.name}</strong><br />
                      <small style={{ color: "#777" }}>{prod.description}</small>
                    </td>
                    <td style={{ padding: "12px", border: "1px solid #ddd", verticalAlign: "middle" }}>${prod.price}</td>
                    <td style={{ padding: "12px", border: "1px solid #ddd", verticalAlign: "middle", color: prod.stock > 0 ? "green" : "red" }}>{prod.stock} units</td>
                    <td style={{ padding: "12px", border: "1px solid #ddd", verticalAlign: "middle" }}>
                      <button onClick={() => handleEditProductClick(prod)} style={{ marginRight: "8px", background: "#ffc107", color: "#000", border: "none", padding: "6px 12px", borderRadius: "4px", cursor: "pointer", fontWeight: "bold" }}>Edit / Load</button>
                      <button onClick={() => { if (window.confirm(`Permanently wipe out catalog item: "${prod.name}"?`)) adminDeleteProduct(prod.id).then(() => refreshProductList()); }} style={{ background: "#dc3545", color: "#fff", border: "none", padding: "6px 12px", borderRadius: "4px", cursor: "pointer" }}>Delete</button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* =========================================================================
          🔥 NEW: FLOATING ADMINISTRATIVE ALERT PANEL STACK (5-SECOND AUTO-CLEAR)
          ========================================================================= */}
      <div style={{ position: "fixed", bottom: "20px", right: "20px", zIndex: 9999, display: "flex", flexDirection: "column", gap: "10px" }}>
        {notifications.map((notif) => (
          <div 
            key={notif.id} 
            style={{ 
              background: "#212529", 
              color: "#fff", 
              padding: "15px 20px", 
              borderRadius: "6px", 
              boxShadow: "0 4px 12px rgba(0,0,0,0.25)", 
              minWidth: "320px", 
              maxWidth: "400px",
              borderLeft: "5px solid #28a745", 
              animation: "slideIn 0.3s ease-out"
            }}
          >
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "6px" }}>
              <strong style={{ fontSize: "14px" }}>{notif.title}</strong>
              <small style={{ color: "#aaa", fontSize: "11px" }}>{notif.timestamp}</small>
            </div>
            <p style={{ margin: 0, fontSize: "13px", lineHeight: "1.4", color: "#e0e0e0" }}>{notif.message}</p>
          </div>
        ))}
      </div>

    </div>
  );
}

export default AdminPanel;
